sql:
SELECT stock_id
FROM stock_high_low
WHERE year_high > 120;

external_knowledge:
- The 'daily return' refers to the percentage change in a stock's price from the opening price to the closing price on a given day; 
- The 'average daily return' is the mean of the daily returns over a specified period, in this case, the year 2023; 
- The 'sentiment score' is a measure of the attitude or emotional tone towards a stock, with higher scores indicating more positive sentiment; 
- 'Unique users' are distinct individuals who have accessed a stock's information, with no duplicates counted.

sql:
SELECT sentiment_score
FROM stock_sentiments
WHERE stock_id = 1 AND date = '2023-05-02';

SELECT MAX(sentiment_score) AS highest_sentiment
FROM stock_sentiments
WHERE stock_id = 1 AND date = '2023-05-02';

SELECT high AS highest_price
FROM stock_prices
WHERE stock_id = 1 AND date = '2023-05-01';

SELECT AVG(volume) AS avg_volume
FROM stock_volume
WHERE stock_id = 0 AND date = '2023-05-02';
